export default Visualization(({ tokens, parameters }) => {
  const score = tokens[0] || { cumulative_profit: 0, cumulative_units_sold: 0, effective_demand: 0, demand_multiplier: parameters.demand_multiplier || 1, profit_rate: 0 };
  const profit = score.cumulative_profit;
  const rate = score.profit_rate;
  const demand = score.effective_demand;
  const positiveWidth = Math.max(0, Math.min(360, rate / 25));
  const negativeWidth = Math.max(0, Math.min(360, -rate / 25));

  return (
    <svg viewBox="0 0 420 180" style={{ width: "100%", borderRadius: "6px", background: "#0f172a" }}>
      <rect x="0" y="0" width="420" height="180" fill="#0f172a" />
      <text x="18" y="30" fill="#e2e8f0" fontSize="18" fontWeight="700">Profit objective</text>
      <text x="18" y="58" fill="#94a3b8" fontSize="13">cumulative profit: {profit.toFixed(0)}</text>
      <text x="18" y="80" fill="#94a3b8" fontSize="13">profit / period: {rate.toFixed(1)}</text>
      <line x1="210" y1="112" x2="210" y2="142" stroke="#64748b" strokeWidth="2" />
      <rect x={210 - negativeWidth} y="116" width={negativeWidth} height="20" fill="#ef4444" rx="3" />
      <rect x="210" y="116" width={positiveWidth} height="20" fill="#22c55e" rx="3" />
      <text x="18" y="160" fill="#38bdf8" fontSize="12">effective demand {demand.toFixed(1)} · multiplier {score.demand_multiplier.toFixed(2)}</text>
    </svg>
  );
});

