export default Lambda((input, parameters) => {
  const reorderGap = Math.max(0, parameters.reorder_threshold - 80);
  const batchEffect = Math.max(10, parameters.batch_size) / 180;
  const expediteBoost = 1 + Math.max(0, Math.min(1, parameters.expedite_fraction)) * 0.6;
  return Math.max(0, 0.015 * reorderGap * batchEffect * expediteBoost);
});

export default Lambda((input, parameters) => {
  return Math.max(0, parameters.production_rate);
});

export default Lambda((input, parameters) => {
  const baseDemand = 100 * parameters.demand_multiplier;
  const priceEffect = Math.max(0.1, 1 - 0.018 * (parameters.selling_price - 34));
  const marketingEffect = 1 + 0.015 * parameters.marketing_spend;
  return Math.max(0, baseDemand * priceEffect * marketingEffect);
});

differentialEquations.code:
export default Dynamics((tokens, parameters) => {
  const dm = Math.max(0.1, parameters.demand_multiplier);

  const production = parameters.production_rate;
  const reorder = parameters.reorder_threshold;
  const batch = parameters.batch_size;
  const price = parameters.selling_price;
  const expedite = Math.max(0, Math.min(1, parameters.expedite_fraction));
  const marketing = parameters.marketing_spend;

  // Demand implied by pricing and marketing. This mirrors the stochastic
  // Customer demand arrives transition so the score token follows the same
  // economics as the token flow.
  const baseDemand = 100 * dm;
  const priceEffect = Math.max(0.1, 1 - 0.018 * (price - 34));
  const marketingEffect = 1 + 0.015 * marketing;
  const demandArrivals = Math.max(0, baseDemand * priceEffect * marketingEffect);

  // Approximate fulfilled demand by supply capacity. The discrete token metric
  // still uses actual SoldOrders/LostSales counts; this continuous score gives
  // a parameter-aware cumulative economic objective.
  const replenishmentCapacity = Math.max(0, 0.015 * Math.max(0, reorder - 80) * (Math.max(10, batch) / 180) * (1 + expedite * 0.6)) * 10;
  const fulfillableUnits = Math.max(0, Math.min(demandArrivals, production, replenishmentCapacity));
  const expectedLostUnits = Math.max(0, demandArrivals - fulfillableUnits);

  // Economic assumptions, in profit units per simulated second. These make the
  // objective respond to all tunable levers: selling price as revenue,
  // marketing as spend, production as operating cost, and expediting as a
  // premium on replenishment/fulfillment.
  const unitFulfillmentCost = 18;
  const productionCapacityCost = 0.08 * production;
  const marketingCost = marketing;
  const expeditePremium = expedite * (3.5 * fulfillableUnits + 0.04 * reorder + 0.02 * batch);
  const lostSalePenalty = 12 * expectedLostUnits;
  const rawPolicyHoldingCost = 0.015 * reorder + 0.01 * batch;

  const economicProfitRate =
    price * fulfillableUnits -
    unitFulfillmentCost * fulfillableUnits -
    productionCapacityCost -
    marketingCost -
    expeditePremium -
    lostSalePenalty -
    rawPolicyHoldingCost;

  const effectiveDemand = Math.max(
    0,
    demandArrivals + 0.15 * production + 20 * expedite - 0.05 * Math.max(0, reorder - 160)
  );

  return tokens.map((token) => ({
    cumulative_profit: economicProfitRate,
    cumulative_units_sold: fulfillableUnits,
    effective_demand: 3 * (effectiveDemand - token.effective_demand),
    demand_multiplier: 3 * (parameters.demand_multiplier - token.demand_multiplier),
    profit_rate: 3 * (economicProfitRate - token.profit_rate),
    current_production_rate: 3 * (production - token.current_production_rate),
    current_selling_price: 3 * (price - token.current_selling_price),
    current_marketing_spend: 3 * (marketing - token.current_marketing_spend),
    current_expedite_fraction: 3 * (expedite - token.current_expedite_fraction),
  }));
});

